parameters.jsCode:
const estado = {
  nombre_cliente: $fromAI('nombre_cliente'),
  telefono: $fromAI('telefono'),
  fecha_recogida: $fromAI('fecha_recogida'),
  hora_recogida_entrega: $fromAI('hora_recogida_entrega'),
  raciones: $fromAI('raciones'),
  relleno: $fromAI('relleno'),
  tematica_estilo: $fromAI('tematica_estilo'),
  nombre_en_tarta: $fromAI('nombre_en_tarta'),
  revision_manual: $fromAI('revision_manual')
};

return { estado };

const input = $fromAI('fecha_relativa');

const hoy = luxon.DateTime.now().setZone('Europe/Madrid');

let fecha = hoy;

if (input.includes('mañana')) {
  fecha = hoy.plus({ days: 1 });
}

if (input.includes('pasado')) {
  fecha = hoy.plus({ days: 2 });
}

return {
  fecha_iso: fecha.toISODate()
};

const source =
  $input.first().json.guardrailsInput ||
  $input.first().json.output ||
  "";

const prep = $items("Preparar Datos1", 0, 0)[0]?.json || {};

const phoneNumber = prep.phoneNumber || prep.sessionId || "";
const instanceName = prep.instanceName || "";

const parts = source
  .split("||")
  .map(s => s.trim())
  .filter(Boolean)
  .slice(0, 3);

return parts.map((text, index) => ({
  json: {
    phoneNumber,
    instanceName,
    recipient: `${phoneNumber}@s.whatsapp.net`,
    text,
    order: index + 1
  }
}));

// Obtener datos del webhook original
const webhookData = $('Webhook').first().json;
const messageType = webhookData.body.data.messageType;

let userMessage = '';
let phoneNumber = webhookData.body.data.key.remoteJid.replace('@s.whatsapp.net', '');
let pushName = webhookData.body.data.pushName || 'Usuario';

// Determinar el mensaje según el tipo
if (messageType === 'conversation') {
  userMessage = webhookData.body.data.message.conversation;
} else if (messageType === 'extendedTextMessage') {
  userMessage = webhookData.body.data.message.extendedTextMessage.text;
} else if (messageType === 'audioMessage') {
  // Si viene de transcripción
  try {
    const transcription = $('Transcribir con Whisper1').first();
    userMessage = transcription.json.text || '[Audio no transcrito]';
  } catch (e) {
    userMessage = '[Error al transcribir audio]';
  }
}

return [{
  json: {
    chatInput: userMessage,
    sessionId: phoneNumber,
    phoneNumber: phoneNumber,
    pushName: pushName,
    instanceName: webhookData.body.instance,
    messageType: messageType,
    timestamp: new Date().toISOString()
  }
}];

const original = $('Preparar Datos1').first().json;
return [{
  json: {
    ...original,
    contactoProtegido: true,
    contactoTelefono: $json.Telefono || '',
    contactoNombre: $json.Nombre || '',
    contactoCategoria: ($json.Categoria || '').toString(),
    contactoAccion: ($json.Accion || '').toString().toLowerCase(),
    contactoActivo: ($json.Activo || 'SI').toString(),
    contactoNotas: $json.Notas || ''
  }
}];

const msg = (($json.chatInput || '') + '').toLowerCase();
const keywords = [
  'tarta','tartas','pastel','cumple','cumpleaños','mesa dulce','mesas dulces',
  'candy bar','comunion','comunión','boda','bautizo','taller','talleres',
  'precio','precios','presupuesto','encargo','pedido','pedir','reserva',
  'disponibilidad','fecha','ejemplo','ejemplos','foto','fotos','referencia','referencias'
];
const hits = keywords.filter(k => msg.includes(k));
return [{
  json: {
    ...$json,
    esNegocio: hits.length > 0,
    coincidenciasNegocio: hits.join(', '),
    motivoFiltro: hits.length > 0
      ? 'Contacto protegido con posible intención de negocio'
      : 'Contacto protegido bloqueado sin intención de negocio'
  }
}];

